    /**
     * Checks if this LPAR is the opening parenthesis of a function type that is wrapped inside a nullable type.
     * This is used to avoid reporting unnecessary newline errors for inner function type parameter lists
     * that were correctly wrapped as part of the wrapNullableType logic.
     */
    private fun ASTNode.isInnerLParOfWrappedNullableFunctionType(): Boolean {
        require(elementType == LPAR)

        // Check if this LPAR belongs to a VALUE_PARAMETER_LIST
        val parameterList = treeParent?.takeIf { it.elementType == VALUE_PARAMETER_LIST } ?: return false

