        val nullableType = functionType.treeParent?.takeIf { it.elementType == NULLABLE_TYPE } ?: return false

        // Check if the nullable type exceeds max line length (this would trigger wrapNullableType)
        return (nullableType.column - 1 + nullableType.textLength) > maxLineLength
    }"}

